var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"말루프 씨가 관리국 시니어라면… 여기 있는 민하 씨는?","JPN":"マルーフさんが管理局のシニアなら……ここにいるミウさんは？","ENG":"If you're an Administration Senior... then what about Minha here?","TWN":"如果瑪盧夫是管理局Senior……那這位敏荷是？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그라운드 원의 공인 카운터지.","JPN":"グラウンド・ワンの公認カウンターだ。","ENG":"She's Ground One's Official Counter.","TWN":"她是G1的認證制裁者。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이렇게 어린 사람이 공인 카운터라니… 처음 알았어요.","JPN":"こんな若い方が公認カウンターだなんて……知らなかったです。","ENG":"I had no idea someone so young could be an Official Counter...","TWN":"這麼年輕就是認證制裁者……我還是第一次知道。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"공인 카운터의 정체를 그곳 거주민들이 알고 있을 의무는 없으니까.","JPN":"公認カウンターの正体を市民が知る必要はないからな。","ENG":"Residents aren't obligated to know the identity of their Official Counter.","TWN":"居民本來就沒有義務知道認證制裁者的身分。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그걸 감안해도, 민하가 지금껏 그라운드 원에 얼굴을 거의 비추지 않았던 건 사실이야. 직무유기, 업무태만이지.","JPN":"とはいえ、ミウが今までグラウンド・ワンにほどんど顔を出さなかったのは事実。職務放棄、業務怠慢だ。","ENG":"Even so, it's true that Minha has barely shown her face in Ground One. Negligence. Dereliction of duty.","TWN":"即便如此，敏荷至今幾乎沒在G1露面也是事實。說她瀆職、怠惰也不為過。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"공인 카운터 자리 넘겨 받겠다고 한 적 없다 뭐. 시니어가 멋대로 떠맡겼을 뿐이야.","JPN":"公認カウンターを引き継ぐなんて一言も言ってないし。シニアが勝手に押し付けただけ。","ENG":"It's not like I ever asked to inherit the position. The Senior dumped it on me on his own.","TWN":"我可沒說過要接這個位子，是Senior擅自丟給我的。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"난 세상을 떠돌면서 사람들을 구하느라 바빴다고.","JPN":"私は世界を巡って人助けするのに忙しかったの。","ENG":"I was busy traveling the world, saving people.","TWN":"我忙著在世界各地救人。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"사람들을 구하고 다녔다고요?","JPN":"人助けをして回っていたんですか？","ENG":"Saving people?","TWN":"救人？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"민하는 위험에 처한 사람들을 구하고 감사를 받으면 희열을 느끼는 성향이거든.","JPN":"ミウは危機に陥った人を助けて感謝されることに悦びを感じるタイプでな。","ENG":"Minha has a tendency to feel exhilarated when she rescues people and receives their gratitude.","TWN":"敏荷是那種救了人後，只要收到感謝就會感到興奮的類型。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아마 널 도와줄 때도 자기가 은인이니 감사하라느니 신나서 떠들어댔겠지. 일종의 메시아 신드롬이야.","JPN":"おそらく、あなたを助けたときも恩人だの感謝しろだの、さぞうるさかったんじゃないか？　一種の救済者願望だな。","ENG":"She probably got excited and went on about being your life-saver when she helped you, too. A sort of messiah complex.","TWN":"她幫你的時候應該也自稱恩人、一邊得意洋洋吧？算是某種救世主症候群。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"저기요, 말루프 씨. 그렇게 말하면 내가 미친■ 같잖아.","JPN":"ちょっとマルーフさん。そんな言い方したら私が変な風に思われるじゃない。","ENG":"Hey, Ms. Maalouf. When you put it like that, I sound crazy.","TWN":"喂，瑪盧夫，你這樣講我聽起來很像瘋■子欸。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그게 아니면 공인 카운터의 역할을 내팽개치고서 방방곡곡 떠돌 다른 이유라도 있나?","JPN":"なら、公認カウンターの役目を放棄し、各地を放浪している別の理由でもあるのか？","ENG":"If that's not it, then why abandon your role as Official Counter and wander all over the place?","TWN":"不然還有什麼理由，會把認證制裁者的職責丟著不管，到處亂跑？"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그건…","JPN":"それは……","ENG":"That's...","TWN":"那是……"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"쳇, 몰라. 맘대로 생각해.","JPN":"ちっ、勝手にそう思ってれば。","ENG":"Tch, whatever. Think what you want.","TWN":"嘖，算了。隨你怎麼想。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"앞서 말했듯이, 우리는 그라운드 원에 숨어 들어온 침입자들의 행방을 추적하고 있어.","JPN":"先程も話したが、私たちはグラウンド・ワンに忍びこんだ侵入者たちの行方を追っている。","ENG":"As I said earlier, we're tracking intruders who slipped into Ground One.","TWN":"如我所說，我們正在追查潛入G1的入侵者。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 결과, 당신이 일하는 가게에 잠입을 하게 됐고, 녀석들이 무엇을 노리는지 알게 됐지.","JPN":"その結果、あなたが働いている店にたどり着き、やつらの狙いがわかったというわけだ。","ENG":"That investigation led us to the bar where you work, and to what they're after.","TWN":"調查結果顯示，他們潛入你工作的店，也確定他們的目標。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모… 말씀이시죠?","JPN":"モモ……ですよね？","ENG":"You mean Momo...?","TWN":"是指……莫莫吧？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"對。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 모모란 아이에 대해, 알고 있는대로 설명해주면 고맙겠군.","JPN":"そのモモという子について、知っている情報を教えてくれると助かる。","ENG":"I'd appreciate it if you told us everything you know about that child.","TWN":"關於那個叫莫莫的孩子，把你知道的都說出來吧。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모는…","JPN":"モモは……","ENG":"Momo...","TWN":"莫莫她……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"달콤한 걸 좋아하고, 이상할 정도로 운이 나빠서 항상 가는 곳마다 문제를 일으키는 사고뭉치에요.","JPN":"甘いものが好きで、おかしいほど運が悪くて、いつも行く先々でトラブルを起こす問題児です。","ENG":"Loves sweets, and a walking disaster who has unbelievably bad luck, causing trouble wherever she goes.","TWN":"喜歡甜食，而且運氣異常的差。是個走到哪裡都會出事的麻煩製造機。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저도 그 밖의 정보는 모르고요.","JPN":"私の知っていることと言えば、それくらいです。","ENG":"That's all I really know.","TWN":"我也只知道這些。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"침입자들이 악마라고 불렀을 때, 언니는 분명 거기에 반응했지?","JPN":"侵入者たちがあの子を悪魔って呼んだとき、姉さん反応したよね？","ENG":"When the intruders called her a devil, you clearly reacted, didn't you?","TWN":"入侵者稱她為魔鬼時，你明顯有反應對吧？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뭔가 숨기고 있는 게 있다면, 너무 늦기 전에 털어놓는 게 어때?","JPN":"何か隠しているんなら早めに話すことをお勧めするけどね。","ENG":"If there's something you're hiding, why not come clean before it's too late?","TWN":"如果還有隱瞞的，趁早說出來吧？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"처음 모모를 만났을 땐… 저도 악마일 거라 생각했어요.","JPN":"初めてモモに出会った時は……私も悪魔だと思いました。","ENG":"When I first met Momo... I thought she was a devil too.","TWN":"第一次見到莫莫時……我也以為她是魔鬼。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"장식이 아닌 진짜 뿔이 달려있었고, 악마를 찾는 펜듈럼은 그 가게에서만 반응했으니까.","JPN":"飾りじゃない本物の角が生えていたし、悪魔を指し示すペンデュラムはその店でしか反応しませんでしたから。","ENG":"She had real horns, not decorations, and the devil-detecting pendulum only reacted inside that bar.","TWN":"她有真正的角，而且尋找魔鬼的鐘擺只在那間店裡有反應。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하지만 지금은… 잘 모르겠네요.","JPN":"でも今は……よくわかりません。","ENG":"But now... I'm not sure anymore.","TWN":"但現在……我也說不上來了。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 아이가 진짜 악마인지, 설령 악마라해도 그런 악마가 제거해야 할만큼 나쁜 존재인 건지.","JPN":"あの子が本当に悪魔なのか、仮にそうだとしても、殺さねばならないほど悪しき存在なのか。","ENG":"Whether she's truly a devil, and even if she is, whether she's a devil so evil that she deserves to be eliminated.","TWN":"她到底是不是魔鬼；就算是，是否真的壞到必須被消滅。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"악마가 나쁜 존재인지 모르겠다라- 내가 아는 구마사가 입에 담을 법한 이야긴 아니군.","JPN":"悪魔が悪しき存在なのかよくわからない、か。私の知る限り、エクソシストが口にするような言葉ではないな。","ENG":"Not knowing whether devils are evil... Hardly something I'd expect to hear from an exorcist.","TWN":"不知道魔鬼到底壞不壞——這可不像我認識的驅魔師會說的話。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"만약 모모가 악마라면… 관리국은 어떤 조치를 취하게 되는 거죠?","JPN":"もしモモが悪魔なら……管理局はどうするつもりですか？","ENG":"If Momo really is a devil... what would the Administration do?","TWN":"如果莫莫真的是魔鬼……管理局會採取什麼行動？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 적을 판가름하는 기준은 악마냐 아니냐가 아니라, 도시에 위협이 될 가능성에 달려있다.","JPN":"管理局が敵と判断する基準は、悪魔か否かではなく、都市の脅威になるか否かだ。","ENG":"The Administration doesn't judge enemies based on whether they're devils, but on whether they pose a threat to the city.","TWN":"管理局判定敵人的標準，不在於是不是魔鬼，而在於是否可能威脅城市。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"평범한 사람이건, 카운터 범죄자건, 악마건, 내 관할에서 문제를 일으켰다면 관리국 규정에 따라 대응할 뿐이지.","JPN":"普通の人間であろうが、カウンター犯罪者であろうが、ましてや悪魔であろうが。私の管轄区域で問題を起こしたなら管理局の規定に沿って対応するだけだ。","ENG":"Whether it's an ordinary civilian, a criminal Counter, or a devil, if they cause trouble in my jurisdiction, we respond according to Administration regulations.","TWN":"不論是普通人、制裁者罪犯還是魔鬼，只要在我管轄範圍內製造問題，就按規定處理。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"언니가 말하는 악마란 존재가 얼마나 위험한진 몰라도, 침입자들은 이미 그라운드 원에서 사람을 해쳤어.","JPN":"姉さんの言う悪魔ってのがどれほど危険なのかはわからないけど、侵入者たちはもうグラウンド・ワンで人を殺めた。","ENG":"I don't know how dangerous the kind of devil you're talking about is, but the intruders have already hurt people in Ground One.","TWN":"不管你口中的魔鬼有多危險，入侵者已經在G1傷害人了。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};